import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_packages(data):
    result = {}
    for project in data.get('projects', []):
        pname = project['path'].split('/')[-1]
        pkgs = {}
        for fw in project.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg['resolvedVersion']
        result[pname] = pkgs
    return result

b = get_packages(baseline)
a = get_packages(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes = True
            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  None')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(bp.keys()):
        if bp.get(pkg) == ap.get(pkg):
            print(f'  {proj}: {pkg} {bp[pkg]}')
"

